## Summary

The `/v1/messages` endpoint returns invalid tool call arguments json when using mistral models, such as `mistralai/Ministral-3-14B-Instruct-2512`, thus breaking Claude code.

This only happens for the `/v1/messages` endpoint (other models, such as `openai/gpt-oss-120b`, are not affected).


## Analysis and solution

The cause for this is that for mistral models the `create_chat_completion` generates the first delta for tool calls along with the first arguments json delta, like this:

```json
"delta": {
    "tool_calls": [
        {"id": "O4kbyHTo9", "type": "function", "index": 0, "function": { "name": "execute_bash_code", "arguments": "{\"" } }}
    ]
}
```

The current implementation of `message_stream_converter` generates a `AnthropicStreamEvent(type="content_block_start", ...)` when a tool calls object is seen with a non-null `id` and immediately streams it back to the client, discarding any function arguments (if present),
incorrectly assuming that the first delta will only contain the tool call id and function name.

The solution is to create and stream an `AnthropicStreamEvent(type='content_block_delta', ...)` with the partial json function arguments right after the `content_block_start` event is created and streamed.

### Reproducer

This reproducer can be used to test the issue. set `ANTHROPIC_BASE_URL` (and `ANTHROPIC_AUTH_TOKEN` if required). In order to test with claude code, `ANTHROPIC_MODEL` also needs to be set:

```bash
ANTHROPIC_MODEL=$(curl ${ANTHROPIC_BASE_URL}/v1/models -H Authorization:"bearer $OPENAI_API_KEY" | jq -r '.data[0].id')
```

<details>

<summary> anthropic_tool_call_streaming.py (click to expand) </summary>

```python
import json
import os
from datetime import datetime

import requests

# Configuration
ANTHROPIC_BASE_URL = os.getenv("ANTHROPIC_BASE_URL", "http://localhost:8000")
ANTHROPIC_AUTH_TOKEN = os.getenv("ANTHROPIC_AUTH_TOKEN", os.getenv("OPENAI_API_KEY"))
API_URL = f"{ANTHROPIC_BASE_URL}/v1/messages"

MODEL = requests.get(
    f"{ANTHROPIC_BASE_URL}/v1/models",
    headers={"Authorization": f"bearer {ANTHROPIC_AUTH_TOKEN}"}
    if ANTHROPIC_AUTH_TOKEN
    else {},
).json()["data"][0]["id"]


# Logging setup
LOG_FILE = "invalid_tool_input.log"


def log_invalid_json(raw_input: str, error: str):
    """Logs invalid JSON input to a file with a timestamp."""
    timestamp = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    log_entry = f"[{timestamp}] Error: {error}\nRaw Input: {raw_input}\n\n"
    with open(LOG_FILE, "a") as f:
        f.write(log_entry)


# Tool definition
def execute_bash_code(code: str):
    """Executes the given bash code and returns the output."""
    try:
        result = os.popen(code).read()
        return result.strip() if result else "Command executed successfully, no output."
    except Exception as e:
        return f"Error executing command: {str(e)}"


# Tool schema
tools = [
    {
        "name": "execute_bash_code",
        "description": "Executes the given bash code and returns the output.",
        "input_schema": {
            "type": "object",
            "properties": {
                "code": {"type": "string", "description": "The bash code to execute."}
            },
            "required": ["code"],
        },
    }
]


# API call to Anthropic-compatible endpoint with streaming
def call_anthropic_api_streaming(messages, tools):
    headers = {
        "Content-Type": "application/json",
        "Authorization": f"Bearer {ANTHROPIC_AUTH_TOKEN}",
        "anthropic-version": "2023-06-01",
    }

    payload = {
        "model": MODEL,
        "messages": messages,
        "tools": tools,
        "max_tokens": 1024,
        "stream": True,
    }

    print(f"Sending payload: {json.dumps(payload, indent=2)}")
    with requests.post(API_URL, headers=headers, json=payload, stream=True) as response:
        response.raise_for_status()
        for line in response.iter_lines():
            if not line:
                continue

            decoded_line = line.decode("utf-8")
            if not decoded_line.startswith("data: "):
                continue

            try:
                data = json.loads(decoded_line[6:])
                yield data
            except json.JSONDecodeError as e:
                print(f"Warning: Failed to parse streaming chunk: {e}")
                continue


# Main interaction loop
def main():
    messages = [
        {
            "role": "user",
            "content": "What is the current uptime? Use the bash tool to fetch it.",
        }
    ]

    # Step 1: Get tool call from model via streaming
    tool_use = None
    current_tool_id = None
    current_tool_name = None
    tool_input = {}
    input_buffer = ""

    print("Starting stream...")
    for chunk in call_anthropic_api_streaming(messages, tools):
        print(f"Processed chunk: {chunk}")  # Debug print

        if chunk.get("type") == "content_block_start":
            if chunk.get("content_block", {}).get("type") == "tool_use":
                current_tool_id = chunk["content_block"]["id"]
                current_tool_name = chunk["content_block"]["name"]
                tool_input = {}
                input_buffer = ""

        elif chunk.get("type") == "content_block_delta":
            if chunk.get("delta", {}).get("type") == "input_json_delta":
                input_delta = chunk["delta"]["partial_json"]
                if input_delta:
                    input_buffer += input_delta

        elif chunk.get("type") == "content_block_stop":
            if not (current_tool_id and current_tool_name):
                continueMinimal reproducer 

            try:
                tool_input = json.loads(input_buffer.strip())
            except json.JSONDecodeError as e:
                print(
                    f"Warning: Failed to parse tool input JSON. Check {LOG_FILE} for details."
                )
                log_invalid_json(input_buffer, str(e))
                tool_use = None
                continue

            tool_use = {
                "id": current_tool_id,
                "name": current_tool_name,
                "input": tool_input,
            }
            break

    if tool_use:
        print(f"Tool use: {tool_use}")  # Debug print
        # Step 2: Execute tool and prepare response
        if tool_use["name"] == "execute_bash_code":
            code = tool_use["input"].get("code", "uptime")
            tool_result = execute_bash_code(code)

            # Append tool result to messages
            messages.append(
                {
                    "role": "assistant",
                    "content": [
                        {
                            "type": "tool_use",
                            "name": tool_use["name"],
                            "id": tool_use["id"],
                            "input": tool_use["input"],
                        }
                    ],
                }
            )
            messages.append(
                {
                    "role": "user",
                    "content": [
                        {
                            "type": "tool_result",
                            "tool_use_id": tool_use["id"],
                            "content": tool_result,
                        }
                    ],
                }
            )

            # Step 3: Get final response from model via streaming
            print("Final response:")
            for chunk in call_anthropic_api_streaming(messages, tools):
                if chunk.get("type") == "content_block_delta" and chunk.get(
                    "delta", {}
                ).get("text"):
                    print(chunk["delta"]["text"], end="", flush=True)
            print()


if __name__ == "__main__":
    main()

```

</details>


### Reproducer output

These are the invalid chunks returned by `/v1/messages`:
```
Processed chunk: {'type': 'message_start', 'message': {'id': 'chatcmpl-b64327adde8db264', 'content': [], 'model': 'mistralai/Ministral-3-14B-Instruct-2512', 'usage': {'input_tokens': 94, 'output_tokens': 0}}}
Processed chunk: {'type': 'content_block_start', 'content_block': {'type': 'tool_use', 'id': 'O4kbyHTo9', 'name': 'execute_bash_code', 'input': {}}, 'index': 0}
Processed chunk: {'type': 'content_block_delta', 'delta': {'type': 'input_json_delta', 'partial_json': 'code'}, 'index': 0}
Processed chunk: {'type': 'content_block_delta', 'delta': {'type': 'input_json_delta', 'partial_json': '":'}, 'index': 0}
